import React, { useState } from 'react';
import FichaExpandidaEditable from '../components/FichaExpandidaEditable';
const DashboardPage = () => {
  const [empresaDemo, setEmpresaDemo] = useState({
    id_empresa: 1,
    nombre_comercial: "Súper Empresa S.A.",
    denominacion_social: "Súper Empresa Sociedad Anónima",
    nit: "123456789",
    url: "demo_empresa.jpg",
    fecha_fundacion: "2000-01-01",
    fecha_cierre: null,
    eslogan: "Innovando el futuro",
    descripcion: "Esta es una empresa demostrativa cargada desde el Dashboard.",
    rubros: [{ nombre_rubro: "Tecnología" }],
    propietarios: [
      {
        nombre: "Juan",
        apellido_paterno: "Pérez",
        apellido_materno: "Gómez"
      }
    ]
  });

  return (
    <div className="min-h-screen w-full flex items-center justify-center bg-gray-100">
      <FichaExpandidaEditable
        empresa={empresaDemo}
        onClose={() => alert('Cerrando sin guardar')}
      />
    </div>
  );
};

export default DashboardPage;
